import httpx
import json
import sys

url = "http://are-sidecar:8000/mcp"

class MCPClient:
    def __init__(self):
        self.session_id = httpx.options(url).headers.get("mcp-session-id")
        self.headers = {
            "Content-Type": "application/json",
            "Accept": "application/json, text/event-stream",
            "mcp-session-id": self.session_id
        }
        self.msg_id = 1

    def send_request(self, method, params=None):
        payload = {
            "jsonrpc": "2.0",
            "id": self.msg_id,
            "method": method
        }
        if params is not None:
            payload["params"] = params
        self.msg_id += 1

        r = httpx.post(url, json=payload, headers=self.headers, timeout=60.0)
        for line in r.text.splitlines():
            if line.startswith("data: "):
                return json.loads(line[6:])
        return r.text

    def send_notification(self, method, params=None):
        payload = {
            "jsonrpc": "2.0",
            "method": method
        }
        if params is not None:
            payload["params"] = params
        httpx.post(url, json=payload, headers=self.headers, timeout=60.0)

    def initialize(self):
        res = self.send_request("initialize", {
            "protocolVersion": "2024-11-05",
            "capabilities": {},
            "clientInfo": {"name": "test", "version": "1.0"}
        })
        self.send_notification("notifications/initialized")
